patch:
diff --git a/llvm/lib/Transforms/Utils/LoopPeel.cpp b/llvm/lib/Transforms/Utils/LoopPeel.cpp
index bd025fddd0cf..e6da3b1f26c8 100644
--- a/llvm/lib/Transforms/Utils/LoopPeel.cpp
+++ b/llvm/lib/Transforms/Utils/LoopPeel.cpp
@@ -1257,7 +1257,14 @@ bool llvm::peelLoop(Loop *L, unsigned PeelCount, bool PeelLast, LoopInfo *LI,
     // Now adjust users of the original exit values by replacing them with the
     // exit value from the peeled iteration and remove them.
     for (const auto &[P, E] : ExitValues) {
-      P->replaceAllUsesWith(isa<Constant>(E) ? E : &*VMap.lookup(E));
+      Value *Replacement = E;
+      if (!isa<Constant>(E)) {
+        // Only look up in VMap if E is defined within the loop being peeled.
+        if (auto *EI = dyn_cast<Instruction>(E))
+          if (L->contains(EI))
+            Replacement = &*VMap.lookup(E);
+      }
+      P->replaceAllUsesWith(Replacement);
       P->eraseFromParent();
     }
     formLCSSA(*L, DT, LI, SE);

